// ── Determine strategy, build email, prepare DB payloads ──

const DRIVER_LABELS = {
  days_since_last_login: 'low login activity',
  events_per_month_trend: 'declining event creation',
  support_ticket_velocity: 'frequent support tickets',
  tenure_months: 'early tenure phase',
  monthly_charges: 'plan cost concerns',
  annual_revenue: 'revenue mismatch',
  has_dedicated_csm: 'lack of dedicated CSM',
  payment_auto: 'manual payment friction',
  paperless_billing: 'billing preferences',
  online_security: 'security feature gap',
  online_backup: 'backup feature gap',
  streaming_tv: 'unused streaming features',
  senior_citizen: 'demographic factor',
  has_partner: 'demographic factor',
  has_dependents: 'demographic factor',
  plan_type: 'plan type mismatch',
  platform_tier: 'platform tier limitations',
};

function driverLabel(driver) {
  return DRIVER_LABELS[driver] || driver.replace(/_/g, ' ');
}

function parseDrivers(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') {
    try { return JSON.parse(raw); } catch { return []; }
  }
  return Array.isArray(raw) ? raw : [];
}

function productTipFor(driver) {
  const tips = {
    days_since_last_login: { feature: 'Event Dashboard', tip: 'Your personalized Event Dashboard shows upcoming deadlines and attendee RSVPs at a glance — no need to dig through emails.' },
    events_per_month_trend: { feature: 'AI Agenda Builder', tip: 'Our AI Agenda Builder can create a full event program in minutes. Customers who use it run 3x more events per quarter.' },
    support_ticket_velocity: { feature: 'Help Center & Live Chat', tip: 'Our revamped Help Center has step-by-step guides for the most common workflows — many customers find answers faster than opening a ticket.' },
  };
  return tips[driver] || { feature: 'Live Polling', tip: 'Live Polling lets your attendees interact in real time — it is our most-loved feature with a 94% satisfaction rate.' };
}

const items = $input.all();
const results = [];

for (const item of items) {
  const a = item.json;
  const risk = a.risk_tier;
  const arr = parseFloat(a.annual_revenue) || 0;
  const drivers = parseDrivers(a.churn_drivers);
  const topDriverKey = drivers.length > 0 ? drivers[0].driver : 'days_since_last_login';
  const topDriverLabel = driverLabel(topDriverKey);
  const firstName = (a.name || '').split(' ')[0] || a.name;

  let strategy, taskPriority, caseNeeded, emailSubject, emailBody;

  // ── Decision logic from prompt.md ──
  if (risk === 'Critical' && arr > 50000) {
    strategy = 'csm_escalation';
    taskPriority = 'Urgent';
    caseNeeded = true;
    emailSubject = `${firstName}, your dedicated success team is ready to help`;
    emailBody = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">`
      + `<h2 style="color:#1a1a2e;">Hi ${firstName},</h2>`
      + `<p>I'm <strong>{{CSM_NAME}}</strong>, your dedicated Customer Success Manager at NovaSeat.</p>`
      + `<p>We noticed some signals that suggest you might not be getting full value from the platform — specifically <strong>${topDriverLabel}</strong>.</p>`
      + `<p>Given how important NovaSeat is to your event operations, I'd love to schedule a quick call to understand what's going on and see how we can help.</p>`
      + `<p><a href="{{CALENDAR_LINK}}" style="display:inline-block;background:#4f46e5;color:#fff;padding:12px 24px;border-radius:6px;text-decoration:none;font-weight:bold;">Book a 15-min call with me</a></p>`
      + `<p>Or simply reply to this email — I read every response personally.</p>`
      + `<p style="margin-top:24px;">Best,<br/><strong>{{CSM_NAME}}</strong><br/>Customer Success, NovaSeat</p>`
      + `</div>`;

  } else if (risk === 'Critical') {
    strategy = 'auto_outreach';
    taskPriority = 'High';
    caseNeeded = false;
    emailSubject = `${firstName}, let's get NovaSeat working better for you`;
    emailBody = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">`
      + `<h2 style="color:#1a1a2e;">Hi ${firstName},</h2>`
      + `<p>We've noticed some changes in how you're using NovaSeat — particularly <strong>${topDriverLabel}</strong> — and we want to make sure everything is running smoothly.</p>`
      + `<p>Here are a few things that might help:</p>`
      + `<ul>`
      + `<li><strong>Book a free success call</strong> — we'll walk through your setup and optimize it: <a href="{{CALENDAR_LINK}}">Pick a time</a></li>`
      + `<li><strong>Reply to this email</strong> with any questions or concerns</li>`
      + `<li><strong>Visit our Help Center</strong> for quick self-service guides</li>`
      + `</ul>`
      + `<p>We're here to help you get the most out of every event.</p>`
      + `<p style="margin-top:24px;">The NovaSeat Team</p>`
      + `</div>`;

  } else {
    // High risk → product tip
    strategy = 'product_tip';
    taskPriority = 'Medium';
    caseNeeded = false;
    const tip = productTipFor(topDriverKey);
    emailSubject = `${firstName}, have you tried ${tip.feature}?`;
    emailBody = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">`
      + `<h2 style="color:#1a1a2e;">Hi ${firstName},</h2>`
      + `<p>We wanted to share a feature that customers in a similar situation find really valuable:</p>`
      + `<div style="background:#f8f7ff;border-left:4px solid #4f46e5;padding:16px;margin:16px 0;border-radius:4px;">`
      + `<strong>${tip.feature}</strong><br/>${tip.tip}`
      + `</div>`
      + `<p>If you'd like a quick walkthrough, just reply to this email or <a href="{{CALENDAR_LINK}}">book a 10-minute demo</a>.</p>`
      + `<p style="margin-top:24px;">The NovaSeat Team</p>`
      + `</div>`;
  }

  results.push({
    json: {
      // account data (pass through)
      account_id: a.id,
      account_name: a.name,
      account_email: a.email,
      annual_revenue: arr,
      plan_type: a.plan_type,
      risk_tier: risk,
      churn_probability: a.churn_probability,
      churn_drivers: a.churn_drivers,
      csm_id: a.csm_id,
      csm_name: a.csm_name,
      csm_email: a.csm_email,
      days_since_last_login: a.days_since_last_login,
      // computed
      strategy,
      taskPriority,
      caseNeeded,
      emailSubject,
      emailBody,
      taskTitle: `Follow up: ${a.name} — ${risk} risk (${strategy})`,
      taskDescription: `Account ${a.name} flagged as ${risk} risk (churn probability ${a.churn_probability}). Top driver: ${topDriverLabel}. Strategy: ${strategy}.`,
    }
  });
}

return results;

// Merge intervention ID with previous data
const prev = $('Determine Strategy & Build Email').item.json;
const interventionId = $json.id;
return [{ json: { ...prev, intervention_id: interventionId } }];
